DROP TABLE IF EXISTS `predictions`;
CREATE TABLE `predictions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `anio` smallint unsigned NOT NULL,
  `mes` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `scenario` enum('OPTIMIST','BASE','PESSIMIST') COLLATE utf8mb4_unicode_ci NOT NULL,
  `metric_type` enum('OCC','ADR','REV','RN') COLLATE utf8mb4_unicode_ci NOT NULL,
  `value` decimal(15,4) NOT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_pred_nat` (`anio`,`mes`,`scenario`,`metric_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

